import json

# Get business data from storage
businesses = locals()['var_functions.query_db:50']

# Map businesses by ID
business_map = {}
category_mapping = {}

for business in businesses:
    business_id = business['business_id']
    description = business.get('description', '')

    business_map[business_id] = description

    # Parse categories from description
    import re

    # Pattern 1: after "services in" or "services including"
    patterns = [
        r'offers[^.]*services[^:]*in([^\.]+)',
        r'offers[^.]*services[^:]*including[^:]*([^\.]+)',
        r'offers a range of services[^in]*in([^\.]+)',
        r'providing a range of services in([^\.]+)'
    ]

    categories = []
    for pattern in patterns:
        matches = re.findall(pattern, description, re.IGNORECASE)
        for match in matches:
            # Split by commas
            cats = [cat.strip() for cat in match.split(',')]
            for cat in cats:
                # Handle "and" between categories
                if ' and ' in cat:
                    subcats = [subcat.strip() for subcat in cat.split(' and ')]
                    categories.extend(subcats)
                else:
                    categories.append(cat)

    # Clean up categories
    cleaned = []
    for cat in categories:
        cat = cat.strip()
        # Remove empty and skip location words
        if cat and cat not in ['Saint Petersburg', 'FL', 'Avon', 'IN', 'Tarpon Springs', 'King of Prussia', 'PA', 'Saint Louis', 'MO']:
            cleaned.append(cat)

    category_mapping[business_id] = cleaned

# If we have businesses not in the full collection, try to parse from their descriptions we have
for business in ['businessid_41', 'businessid_33', 'businessid_74', 'businessid_92', 'businessid_10']:
    if business in business_map:
        desc = business_map[business]
        categories = []
        if 'Internal Medicine' in desc:
            categories.extend(['Internal Medicine', 'Doctors', 'Health & Medical'])
        if 'Nail Salons' in desc:
            categories.extend(['Nail Salons', 'Hair Removal', 'Beauty & Spas', 'Waxing'])
        if 'Candy Stores' in desc:
            categories.extend(['Candy Stores', 'Specialty Food', 'Food'])
        if 'Cosmetics & Beauty Supply' in desc:
            categories.extend(['Cosmetics & Beauty Supply', 'Cosmetic Dentists', 'Tanning', 'Teeth Whitening', 
                              'Beauty & Spas', 'Dentists', 'Shopping', 'Blow Dry/Out Services', 
                              'Health & Medical', 'Spray Tanning', 'Hair Salons'])
        if 'Restaurants, Chinese' in desc:
            categories.extend(['Restaurants', 'Chinese'])

        if business not in category_mapping or not category_mapping[business]:
            category_mapping[business] = categories

print('__RESULT__:')
print(json.dumps(category_mapping))

